var chatClient = openAiClient.GetChatClient(modelId).AsIChatClient();

// Wrap in FunctionInvokingChatClient to enable automatic tool dispatch with
// a hard iteration cap to prevent runaway loops.
using var functionClient = new FunctionInvokingChatClient(chatClient)
{
    MaximumIterationsPerRequest = 15,
};

var agent = new ChatClientAgent(
    chatClient: functionClient,
    instructions: """
