    Console.WriteLine($"\nResearching \"{topic}\" — this may take a moment …\n");
    Console.ResetColor();

    try
    {
        var session = await agent.CreateSessionAsync(Guid.NewGuid().ToString());

        await foreach (var update in agent.RunStreamingAsync(
            $"Research the following topic and provide a comprehensive summary:\n\n{topic}",
            session,
