                {
                    Temperature = 0f,
                    MaxOutputTokens = 4096,
                },
            }))
        {
            // Stream the final answer text to the console as it arrives.
            if (update.Content is { Length: > 0 } text)
            {
                Console.Write(text);
            }
        }

        Console.WriteLine("\n");
    }
    catch (Exception ex)
    {
        Console.ForegroundColor = ConsoleColor.Red;
        Console.Error.WriteLine($"Error: {ex.Message}");
        Console.ResetColor();
    }
}

