/// <summary>
/// Provides web-search and page-fetching capabilities using DuckDuckGo's
/// HTML interface (no API key required).
/// </summary>
internal static class WebSearchTool
{
    private static readonly HttpClient Http = CreateHttpClient();

    private static HttpClient CreateHttpClient()
    {
        var handler = new HttpClientHandler
        {
            AutomaticDecompression = DecompressionMethods.GZip | DecompressionMethods.Deflate,
            AllowAutoRedirect = true,
        };
        var client = new HttpClient(handler) { Timeout = TimeSpan.FromSeconds(15) };
        client.DefaultRequestHeaders.UserAgent.ParseAdd(
            "Mozilla/5.0 (compatible; ResearchAgent/1.0)");
        return client;
    }

    [Description("Search the web for a query and return a list of result titles, snippets, and URLs.")]
    public static async Task<string> SearchAsync(
        [Description("The search query string")] string query)
    {
        try
        {
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://html.duckduckgo.com/html/?q={encoded}";
            var html = await Http.GetStringAsync(url);

            var results = ParseDuckDuckGoResults(html);

            if (results.Count == 0)
                return "No results found.";

            var sb = new StringBuilder();
            foreach (var r in results.Take(8))
            {
                sb.AppendLine($"**{r.Title}**");
                sb.AppendLine($"  URL: {r.Url}");
                sb.AppendLine($"  {r.Snippet}");
                sb.AppendLine();
            }

            return sb.ToString();
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    [Description("Fetch a web page and return its text content (truncated to ~4000 chars).")]
    public static async Task<string> FetchPageAsync(
        [Description("The full URL to fetch")] string url)
    {
        try
        {
            var html = await Http.GetStringAsync(url);
            var text = StripHtml(html);

            const int maxLen = 4000;
            if (text.Length > maxLen)
                text = text[..maxLen] + "\n\n[… truncated]";

            return text;
        }
        catch (Exception ex)
        {
            return $"Failed to fetch page: {ex.Message}";
        }
    }

    // ------------------------------------------------------------------
    // HTML helpers
    // ------------------------------------------------------------------

    private static List<SearchResult> ParseDuckDuckGoResults(string html)
    {
        var results = new List<SearchResult>();

        // DuckDuckGo HTML results are in <a class="result__a"> with snippets
        // in <a class="result__snippet">.
        var linkPattern = new Regex(
            @"<a[^>]+class=""result__a""[^>]*href=""([^""]+)""[^>]*>(.*?)</a>",
            RegexOptions.Singleline | RegexOptions.IgnoreCase);

        var snippetPattern = new Regex(
            @"<a[^>]+class=""result__snippet""[^>]*>(.*?)</a>",
            RegexOptions.Singleline | RegexOptions.IgnoreCase);

        var links = linkPattern.Matches(html);
        var snippets = snippetPattern.Matches(html);

        for (int i = 0; i < links.Count; i++)
        {
            var rawUrl = links[i].Groups[1].Value;
            var title = StripHtml(links[i].Groups[2].Value).Trim();
            var snippet = i < snippets.Count
                ? StripHtml(snippets[i].Groups[1].Value).Trim()
                : "";

            // DuckDuckGo wraps URLs in a redirect; extract the actual target.
            var actualUrl = ExtractRedirectUrl(rawUrl);

            if (!string.IsNullOrWhiteSpace(title) && !string.IsNullOrWhiteSpace(actualUrl))
                results.Add(new SearchResult(title, actualUrl, snippet));
        }

        return results;
    }

    private static string ExtractRedirectUrl(string ddgUrl)
    {
        // Format: //duckduckgo.com/l/?uddg=<encoded-url>&…
        var match = Regex.Match(ddgUrl, @"uddg=([^&]+)");
        if (match.Success)
            return Uri.UnescapeDataString(match.Groups[1].Value);

        if (ddgUrl.StartsWith("http", StringComparison.OrdinalIgnoreCase))
            return ddgUrl;

        return ddgUrl;
    }

    private static string StripHtml(string html)
    {
        // Remove script/style blocks, then tags, then decode entities.
        var text = Regex.Replace(html, @"<(script|style)[^>]*>.*?</\1>", " ",
            RegexOptions.Singleline | RegexOptions.IgnoreCase);
        text = Regex.Replace(text, @"<[^>]+>", " ");
        text = WebUtility.HtmlDecode(text);
        text = Regex.Replace(text, @"\s{2,}", " ");
        return text.Trim();
    }

    private sealed record SearchResult(string Title, string Url, string Snippet);
}

/// <summary>
/// In-memory notepad the agent uses to collect and review research findings.
/// </summary>
internal sealed class Notepad
{
    private readonly List<string> _notes = [];

    [Description("Save a research note. Include the fact and its source URL.")]
    public string AddNote(
        [Description("The note text, including source citation")] string note)
    {
        _notes.Add(note);
        return $"Note #{_notes.Count} saved.";
    }

    [Description("Read all saved research notes collected so far.")]
    public string ReadNotes()
    {
        if (_notes.Count == 0)
            return "No notes yet.";

        var sb = new StringBuilder();
        for (int i = 0; i < _notes.Count; i++)
            sb.AppendLine($"[{i + 1}] {_notes[i]}");

        return sb.ToString();
    }

    public void Clear() => _notes.Clear();
}

